#include <bits/stdc++.h>
using namespace std;

const int N=10110,M=N*8,INF=1e8;

int n,cnt,deg[N];
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int S,T,f[N],dis[N],pre[N],q[N],ans;
bool inq[N];

void add(int x,int y,int a,int b){
    ver[++tot]=y,edge[tot]=a,val[tot]=b,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,val[tot]=-b,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(dis,0x3f,sizeof(dis));
    memset(inq,0,sizeof(inq));
    int hh=1,tt=0;
    dis[S]=0,f[S]=INF;
    q[++tt]=S;
    inq[S]=1;
    while(hh<=tt){
        int x=q[hh++];
        inq[x]=0;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && dis[y=ver[i]]>dis[x]+val[i]){
                dis[y]=dis[x]+val[i];
                f[y]=min(f[x],edge[i]);
                pre[y]=i; 
                if(!inq[y]) q[++tt]=y,inq[y]=1;
            }
    }
    return dis[T]<INF;
}

void Update(){
    int p=T,flow=f[T];
    ans+=f[T]*dis[T];
    while(p!=S){
        int i=pre[p];
        edge[i]-=flow,edge[i^1]+=flow;
        p=ver[i^1];
    }
}

int main(){
    scanf("%d",&n);
    S=n+1,T=n+2;
    cnt=n+2;
    for(int i=1;i<=n;i++){
        int m,a;
        scanf("%d",&m);
        while(m--){
            scanf("%d",&a);
            cnt++;
            add(i,cnt,INF,0);
            add(cnt,a,INF,0);
            add(cnt,T,1,0);
            deg[a]++;
        }
    }
    for(int i=1;i<=n;i++){
        add(S,i,INF,1);
        if(deg[i])
            add(S,i,deg[i],0);
    }
    while(bfs())
        Update();
    printf("%d",ans);
    return 0;
}
